import subprocess
from pathlib import Path

def run_cmd(command):
    process = subprocess.Popen(command, stdout=subprocess.PIPE)
    
    while True:
        output = process.stdout.readline()
        
        if output == b'' and process.poll():  # Process exited
            break
            
        elif output:                            # Output was not empty, print it out now (without the new line)
          Path('output').write_text(str(output))    
          
    return command.returncode                       # Return code from process execution is returned here 
                                                    # in case of exception or any error then this will be None       
        
if __name__ == "__main__":  
    requirements = Path('requirements.txt').read_text()                       
    
    installs=[f'pip3 install {req} --upgrade' for req in map(str.strip, requirements.splitlines()) if  req]       # List of commands that need to be executed on terminal  
                                                                                   
    run_cmd(' && '.join(installs))                                                  # Joining all the command with '&&', will execute one after another and wait for every execution until completion